  logger.info({
    method: req.method,
    path: req.path,
    ip: req.ip,
  });
  next();
});

// ==================== JWT VERIFICATION ====================
const verifyToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Access token required' });
  }

